import tiktoken
from dataclasses import dataclass, field
from typing import Optional

@dataclass
class TokenBudget:
    """Thread-safe token budget tracker for an OpenAI-compatible model."""
    model: str
    context_limit: int          # e.g. 128_000 for gpt-4o
    output_reserve: int = 4096  # tokens held back for generated response
    safety_margin: float = 0.05 # additional 5% headroom

    _components: dict = field(default_factory=dict, init=False)
    _enc: object = field(default=None, init=False)

    def __post_init__(self):
        self._enc = tiktoken.encoding_for_model(self.model)

    def count(self, text: str) -> int:
        return len(self._enc.encode(text))

    def count_messages(self, messages: list[dict]) -> int:
        """Count tokens including per-message overhead (~4 tokens each)."""
        total = 0
        for msg in messages:
            total += 4  # role + formatting overhead
            content = msg.get("content", "")
            if isinstance(content, str):
                total += self.count(content)
            elif isinstance(content, list):
                for block in content:
                    if block.get("type") == "text":
                        total += self.count(block["text"])
        return total + 2  # conversation priming tokens

    def reserve(self, name: str, text: str) -> int:
        """Count and record tokens for a named component."""
        n = self.count(text)
        self._components[name] = n
        return n

    @property
    def used(self) -> int:
        return sum(self._components.values())

    @property
    def hard_limit(self) -> int:
        return int(self.context_limit * (1 - self.safety_margin)) - self.output_reserve

    @property
    def available(self) -> int:
        return self.hard_limit - self.used

    @property
    def utilization(self) -> float:
        return self.used / self.hard_limit

    def status(self) -> str:
        u = self.utilization
        if u < 0.80:
            return "OK"
        elif u < 0.95:
            return "TRIM"
        else:
            return "COMPRESS"

    def breakdown(self) -> dict:
        return {
            "components": dict(self._components),
            "used": self.used,
            "available": self.available,
            "utilization_pct": round(self.utilization * 100, 1),
            "status": self.status(),
        }

from functools import lru_cache

@lru_cache(maxsize=4096)
def cached_count(text: str) -> int:
    """Cache token counts for stable strings (system prompts, tool schemas, static docs)."""
    return len(enc.encode(text))
